import{_ as r,o as t,c as a,ah as i}from"./chunks/framework.DsjyFzT5.js";const f=JSON.parse('{"title":"AI 工具概览","description":"","frontmatter":{"title":"AI 工具概览","date":"2023-10-15T00:00:00.000Z","category":"AI","tags":["AI"]},"headers":[],"relativePath":"_post/ai/tools.md","filePath":"_post/ai/tools.md"}'),l={name:"_post/ai/tools.md"};function o(n,e,p,h,s,c){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="ai-工具概览" tabindex="-1">AI 工具概览 <a class="header-anchor" href="#ai-工具概览" aria-label="Permalink to &quot;AI 工具概览&quot;">​</a></h1><h2 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h2><p>汇总网站</p><ul><li><a href="https://www.hayo.com/" target="_blank" rel="noreferrer">hayo</a></li><li><a href="https://ai.nancheng.fun/" target="_blank" rel="noreferrer">ai.nancheng.fun</a></li><li><a href="https://www.aigc.casa/" target="_blank" rel="noreferrer">aigc</a></li></ul><p><strong>prompt汇总：</strong></p><ul><li><a href="https://qddmercny4.feishu.cn/sheets/shtcnMklYu0WsXEDUXXanrSEB2m" target="_blank" rel="noreferrer">https://qddmercny4.feishu.cn/sheets/shtcnMklYu0WsXEDUXXanrSEB2m</a></li><li><a href="https://zl49so8lbq.feishu.cn/wiki/wikcnlmCYpKYFrH8ek1sS2ooy8d" target="_blank" rel="noreferrer">https://zl49so8lbq.feishu.cn/wiki/wikcnlmCYpKYFrH8ek1sS2ooy8d</a></li></ul><h2 id="技巧" tabindex="-1">技巧 <a class="header-anchor" href="#技巧" aria-label="Permalink to &quot;技巧&quot;">​</a></h2><ul><li><a href="https://learningprompt.wiki/docs/chatgpt-learning-path" target="_blank" rel="noreferrer">learning prompt</a></li><li><a href="https://zhuanlan.zhihu.com/p/617524191" target="_blank" rel="noreferrer">prompt技巧</a></li><li><a href="https://www.promptingguide.ai/zh" target="_blank" rel="noreferrer">提示工程(Prompt Engineering)</a>，提示词开发和优化</li><li><a href="https://lewlh.github.io/2025/04/15/PromptEngineering" target="_blank" rel="noreferrer">Google提示工程中文翻译</a></li></ul><h2 id="编程相关" tabindex="-1">编程相关 <a class="header-anchor" href="#编程相关" aria-label="Permalink to &quot;编程相关&quot;">​</a></h2><p>ide:</p><ul><li><a href="https://www.cursor.so/" target="_blank" rel="noreferrer">cursor</a></li><li><a href="https://nira.com/github-copilot/" target="_blank" rel="noreferrer">copilot介绍&amp;使用</a></li><li><a href="https://githubnext.com/projects/copilot-labs/" target="_blank" rel="noreferrer">copilot插件</a></li><li><a href="https://github.blog/2023-03-22-github-copilot-x-the-ai-powered-developer-experience/" target="_blank" rel="noreferrer">Copilot X</a></li></ul><h2 id="绘图相关" tabindex="-1">绘图相关 <a class="header-anchor" href="#绘图相关" aria-label="Permalink to &quot;绘图相关&quot;">​</a></h2><ul><li><a href="https://www.8btc.com/article/6774458" target="_blank" rel="noreferrer">midjourney 平替 stable diffusion</a></li><li><a href="https://playgroundai.com/create" target="_blank" rel="noreferrer">stable diffusion 体验</a></li><li><a href="https://yige.baidu.com/" target="_blank" rel="noreferrer">百度文心一格（图片）</a></li><li>豆包</li><li></li></ul><h2 id="综合类" tabindex="-1">综合类 <a class="header-anchor" href="#综合类" aria-label="Permalink to &quot;综合类&quot;">​</a></h2><p>汇总:</p><ul><li><a href="https://poe.com/" target="_blank" rel="noreferrer">poe</a></li><li><a href="https://www.saoma.site/" target="_blank" rel="noreferrer">文案类</a></li><li><a href="https://www.coze.cn/docs/guides/workflow_user_intent" target="_blank" rel="noreferrer">coze</a></li></ul><h3 id="chatgpt" tabindex="-1">chatgpt <a class="header-anchor" href="#chatgpt" aria-label="Permalink to &quot;chatgpt&quot;">​</a></h3><ul><li><a href="https://platform.openai.com/docs/introduction" target="_blank" rel="noreferrer">openai api 官网介绍</a></li></ul><p>免费gpt4：<a href="https://ora.sh/openai/gpt4" target="_blank" rel="noreferrer">https://ora.sh/openai/gpt4</a> 平替：<a href="https://freegpt.one/" target="_blank" rel="noreferrer">https://freegpt.one/</a></p><p><strong>插件系统</strong></p><p><a href="https://github.com/openai/plugins-quickstart" target="_blank" rel="noreferrer">https://github.com/openai/plugins-quickstart</a></p><p>demo：<a href="https://github.com/openai/chatgpt-retrieval-plugin" target="_blank" rel="noreferrer">https://github.com/openai/chatgpt-retrieval-plugin</a></p><blockquote><p>Find an example video of a Retrieval Plugin that has access to the UN Annual Reports from 2018 to 2022 <a href="https://cdn.openai.com/chat-plugins/retrieval-gh-repo-readme/Retrieval-Final.mp4" target="_blank" rel="noreferrer">here</a></p></blockquote><ul><li>介绍文章：<a href="https://mp.weixin.qq.com/s/F2CgJwTC0WUGdziKefjIZA" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/F2CgJwTC0WUGdziKefjIZA</a></li></ul><h3 id="claude" tabindex="-1">claude <a class="header-anchor" href="#claude" aria-label="Permalink to &quot;claude&quot;">​</a></h3><p>弱化版chatgpt：<a href="https://www.anthropic.com/product" target="_blank" rel="noreferrer">https://www.anthropic.com/product</a></p><ul><li>介绍文章：<a href="https://mp.weixin.qq.com/s/QB85YPjh6DMBTPla4NDfXg" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/QB85YPjh6DMBTPla4NDfXg</a></li></ul><h3 id="new-bing" tabindex="-1">new bing <a class="header-anchor" href="#new-bing" aria-label="Permalink to &quot;new bing&quot;">​</a></h3><p>跳转国内解决思路</p><ul><li><a href="https://juejin.cn/post/7202531472720592951" target="_blank" rel="noreferrer">https://juejin.cn/post/7202531472720592951</a></li><li><a href="https://zhuanlan.zhihu.com/p/605970396" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/605970396</a></li></ul><h2 id="生产力工具-其他" tabindex="-1">生产力工具&amp;其他 <a class="header-anchor" href="#生产力工具-其他" aria-label="Permalink to &quot;生产力工具&amp;其他&quot;">​</a></h2><p>gptcommit, cursor, codeium, copilot、newbing</p><p>opencat：客户端gpt工具(似乎api模式，不容易断连)，</p><p>agentgbt: <a href="https://agentgpt.reworkd.ai/" target="_blank" rel="noreferrer">https://agentgpt.reworkd.ai/</a></p><p>飞书：<a href="https://github.com/ConnectAI-E/Feishu-OpenAI" target="_blank" rel="noreferrer">https://github.com/ConnectAI-E/Feishu-OpenAI</a></p><p>ai shell: <a href="https://github.com/BuilderIO/ai-shell" target="_blank" rel="noreferrer">https://github.com/BuilderIO/ai-shell</a></p><p><a href="https://aws.amazon.com/cn/codewhisperer/" target="_blank" rel="noreferrer">https://aws.amazon.com/cn/codewhisperer/</a></p><h2 id="相关资料" tabindex="-1">相关资料 <a class="header-anchor" href="#相关资料" aria-label="Permalink to &quot;相关资料&quot;">​</a></h2><p>推文-ai能做的事：<a href="https://twitter.com/charliecurnin/status/1638942497983598592" target="_blank" rel="noreferrer">https://twitter.com/charliecurnin/status/1638942497983598592</a></p><p>ai相关论文汇总？：<a href="https://briefgpt.xyz/" target="_blank" rel="noreferrer">https://briefgpt.xyz/</a></p><p>LLMs：<a href="https://learnprompting.org/zh-Hans/docs/advanced_applications/mrkl" target="_blank" rel="noreferrer">https://learnprompting.org/zh-Hans/docs/advanced_applications/mrkl</a></p><h2 id="相关文章" tabindex="-1">相关文章 <a class="header-anchor" href="#相关文章" aria-label="Permalink to &quot;相关文章&quot;">​</a></h2><p>「ChatGPT最强竞品」爆火：不限量不要钱免注册！一手实测体验在此：<a href="https://mp.weixin.qq.com/s/QB85YPjh6DMBTPla4NDfXg" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/QB85YPjh6DMBTPla4NDfXg</a></p><p>ChatGPT 插件系统，正式上线： <a href="https://mp.weixin.qq.com/s/F2CgJwTC0WUGdziKefjIZA" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/F2CgJwTC0WUGdziKefjIZA</a></p><p>GPT-5恐被叫停！马斯克、图灵奖得主等千名专家呼吁暂停超强AI研发，至少6个月：<a href="https://mp.weixin.qq.com/s/1AtPzUt0hB5ImSluET8tpA" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/1AtPzUt0hB5ImSluET8tpA</a></p><p>针锋相对！为挑战GPT-4加持的Copilot X，谷歌与拒绝被微软收购的Replit联合发布编码工具：<a href="https://mp.weixin.qq.com/s/T10pBZBtWtbBei43o35E4g" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/T10pBZBtWtbBei43o35E4g</a></p><p>爆火论文打造《西部世界》雏形：25个AI智能体，在虚拟小镇自由成长: <a href="https://mp.weixin.qq.com/s/n0I8Yisi8qNXg9qp4ic5iw" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/n0I8Yisi8qNXg9qp4ic5iw</a></p><p>对话王小川：通用人工智能是一次文艺复兴: <a href="https://mp.weixin.qq.com/s/q3lFEPLb9NE7W6sjBxxLPg" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/q3lFEPLb9NE7W6sjBxxLPg</a></p><p>甲小姐对话王小川：我们已经进入通用人工智能时代｜甲子光年：<a href="https://mp.weixin.qq.com/s/tlYUoqNHarwgQJMx1JNrbg" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/tlYUoqNHarwgQJMx1JNrbg</a></p><p>AutoGPT太火了，无需人类插手自主完成任务，GitHub2.7万星 :<a href="https://mp.weixin.qq.com/s/bV1tPc7hNn2z06YOpzyanw" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/bV1tPc7hNn2z06YOpzyanw</a></p><p>最详细全文翻译！微软155页大工程首次揭示GPT-4超能力（浓缩精华版）：<a href="https://mp.weixin.qq.com/s/-MizP0JdgR5pLKDzlJYZnw" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/-MizP0JdgR5pLKDzlJYZnw</a></p><h2 id="能用ai做什么" tabindex="-1">能用ai做什么 <a class="header-anchor" href="#能用ai做什么" aria-label="Permalink to &quot;能用ai做什么&quot;">​</a></h2><ul><li>代码优化</li><li>让 gpt 总结需求生成 prompt</li><li>总结 sentry 错误规律</li><li>单元测试、开发文档生成</li><li>通过发布内容、浏览情况、社交网络生成人物画像</li><li>代码review + 性能分析</li><li>模拟面试</li></ul><h2 id="gpt开发者领域应用" tabindex="-1">gpt开发者领域应用 <a class="header-anchor" href="#gpt开发者领域应用" aria-label="Permalink to &quot;gpt开发者领域应用&quot;">​</a></h2><blockquote><p><a href="https://twitter.com/Barret_China/status/1638508262739034112" target="_blank" rel="noreferrer">https://twitter.com/Barret_China/status/1638508262739034112</a></p></blockquote><p>1）生成 Commit log，这是 ChatGPT 的强项，它能够快速理解逻辑和代码，通过 diff 归纳出概要，开源的工具有：<a href="https://github.com/zurawiki/gptcommit" target="_blank" rel="noreferrer">https://github.com/zurawiki/gptcommit</a></p><p>2）生成测试用例，团队内实践下来效果相当好。虽然 Copilot 和 Tabnine 等产品在代码自动补全方面已经表现不错，但相较于 <a href="https://codeium.com" target="_blank" rel="noreferrer">https://codeium.com</a> 和 <a href="https://cursor.so" target="_blank" rel="noreferrer">https://cursor.so</a> 这些能够使用自然语言生成代码的体验，还是稍逊一筹。之所以不生成业务代码，是因为生成业务代码需要理解产品逻辑，而编写单元测试只需理解一个函数。</p><p>3）生成 API 文档和代码注释，ChatGPT 可以通过阅读代码，理解函数的输入、输出、功能以及用途，然后生成相应的 API 文档和注释，开源的工具：<a href="https://github.com/awekrx/AutoDoc-ChatGPT" target="_blank" rel="noreferrer">https://github.com/awekrx/AutoDoc-ChatGPT</a></p><p>4）生成 SQL，已经看到 PingCAP 发布了相关产品 chat2query，<a href="https://pingcap.com/chat2query-an-innovative-ai-powered-sql-generator-for-faster-insights/%EF%BC%8C%E5%AF%B9%E5%85%AC%E5%8F%B8%E4%BA%A7%E5%93%81%E3%80%81%E8%BF%90%E8%90%A5%E7%AD%89%E6%9C%89%E6%95%B0%E6%8D%AE%E9%9C%80%E6%B1%82%E4%BD%86%E4%B8%8D%E6%87%82%E6%95%B0%E6%8A%80%E6%9C%AF%E7%9A%84%E5%B2%97%E4%BD%8D%E9%9D%9E%E5%B8%B8%E5%8F%8B%E5%A5%BD%E3%80%82" target="_blank" rel="noreferrer">https://pingcap.com/chat2query-an-innovative-ai-powered-sql-generator-for-faster-insights/，对公司产品、运营等有数据需求但不懂数技术的岗位非常友好。</a></p><p>5）自动代码审查和漏洞检测，ChatGPT 可以分析代码中的潜在问题，包括代码风格不一致、程序逻辑错误或安全漏洞等。这个能力其实在 <a href="http://cursor.so" target="_blank" rel="noreferrer">http://cursor.so</a> 这个产品中就已经具备了，无需等到提交代码，在本地可以直接让程序先完成一轮 CR。</p><p>很多体验做出来都会让人产生 Wow~ 的感觉，利用 ChatGPT 做 toD 方向的建设，确实可以提高开发效率，减少错误，提高代码质量，对公司和开发者还是具有很大价值的。</p>',61)])])}const m=r(l,[["render",o]]);export{f as __pageData,m as default};
